                sorted_arr[tmp_index] = arr[j]
                inversions += k - (mid + 1)  # count inversions involving elements from the right half that are smaller than arr[j]
                j += 1
            else:
                sorted_arr[tmp_index] = arr[k]
                k += 1
            tmp_index += 1

        remaining_left, remaining_right = j, mid + 1
        while remaining_left <= mid and remaining_right <= right:
            if arr[remaining_left] < arr[remaining_right]:
                sorted_arr[tmp_index] = arr[remaining_left]
                inversions += remaining_right - (mid + 1)  # count additional inversions involving the left half's last elements
                remaining_left += 1
            else:
